import{_ as a,o as s,c as e,ag as i}from"./chunks/framework.ePeAWSvT.js";const u=JSON.parse('{"title":"배포 및 공유","description":"","frontmatter":{},"headers":[],"relativePath":"학습자료/2-스킬개념/2-4-배포및공유.md","filePath":"학습자료/2-스킬개념/2-4-배포및공유.md"}'),l={name:"학습자료/2-스킬개념/2-4-배포및공유.md"};function n(o,t,p,d,r,h){return s(),e("div",null,[...t[0]||(t[0]=[i(`<h1 id="배포-및-공유" tabindex="-1">배포 및 공유 <a class="header-anchor" href="#배포-및-공유" aria-label="Permalink to &quot;배포 및 공유&quot;">​</a></h1><p>만든 스킬을 나만 쓰기 아깝지 않나요? GitHub에 올려서 누구나 쓸 수 있게 공유해봅시다.</p><hr><h2 id="왜-배포하나요" tabindex="-1">왜 배포하나요? <a class="header-anchor" href="#왜-배포하나요" aria-label="Permalink to &quot;왜 배포하나요?&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>로컬에만 두기</th><th>GitHub에 올리기</th></tr></thead><tbody><tr><td><strong>백업</strong></td><td>내 컴퓨터 고장 나면 사라짐</td><td>클라우드에 영구 보관</td></tr><tr><td><strong>공유</strong></td><td>USB로 복사해야 함</td><td>링크 하나로 공유</td></tr><tr><td><strong>협업</strong></td><td>나만 사용 가능</td><td>팀 전체가 설치 가능</td></tr><tr><td><strong>버전 관리</strong></td><td>수정하면 이전 버전 사라짐</td><td>모든 변경 이력 보존</td></tr><tr><td><strong>포트폴리오</strong></td><td>나만 알고 있음</td><td>&quot;나는 AI 자동화를 할 줄 아는 사람&quot; 증명</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">핵심</p><p>스킬을 GitHub에 올리면 <strong>백업 + 공유 + 포트폴리오</strong>가 한 번에 해결됩니다.</p></div><hr><h2 id="실습-1-github-cli-설치-로그인" tabindex="-1">실습 1: GitHub CLI 설치 &amp; 로그인 <a class="header-anchor" href="#실습-1-github-cli-설치-로그인" aria-label="Permalink to &quot;실습 1: GitHub CLI 설치 &amp; 로그인&quot;">​</a></h2><p>GitHub에 파일을 올리려면 먼저 준비가 필요합니다. 걱정 마세요 — <strong>Claude Code에게 자연어로 시키면 됩니다.</strong></p><h3 id="step-1-github-계정-만들기-없는-경우" tabindex="-1">Step 1: GitHub 계정 만들기 (없는 경우) <a class="header-anchor" href="#step-1-github-계정-만들기-없는-경우" aria-label="Permalink to &quot;Step 1: GitHub 계정 만들기 (없는 경우)&quot;">​</a></h3><ol><li><a href="https://github.com" target="_blank" rel="noreferrer">github.com</a> 접속</li><li><strong>Sign up</strong> 클릭</li><li>이메일, 비밀번호, 사용자명 입력</li><li>무료 플랜으로 충분합니다</li></ol><div class="tip custom-block"><p class="custom-block-title">이미 계정이 있다면</p><p>바로 Step 2로 넘어가세요!</p></div><h3 id="step-2-github-cli-설치" tabindex="-1">Step 2: GitHub CLI 설치 <a class="header-anchor" href="#step-2-github-cli-설치" aria-label="Permalink to &quot;Step 2: GitHub CLI 설치&quot;">​</a></h3><p>Claude Code 채팅창에 입력하세요:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GitHub CLI(gh)를 설치해줘</span></span></code></pre></div><p>Claude Code가 알아서 운영체제에 맞는 설치 명령어를 실행합니다.</p><h3 id="step-3-github-로그인" tabindex="-1">Step 3: GitHub 로그인 <a class="header-anchor" href="#step-3-github-로그인" aria-label="Permalink to &quot;Step 3: GitHub 로그인&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GitHub에 로그인해줘</span></span></code></pre></div><p>브라우저가 열리면서 인증 화면이 나옵니다. <strong>Authorize</strong> 버튼을 클릭하면 완료!</p><div class="tip custom-block"><p class="custom-block-title">체크포인트</p><p>Claude Code에게 &quot;GitHub 로그인 상태 확인해줘&quot;라고 물어보세요. &quot;Logged in as 사용자명&quot; 이 나오면 성공입니다.</p></div><hr><h2 id="실습-2-내-스킬-github에-올리기" tabindex="-1">실습 2: 내 스킬 GitHub에 올리기 <a class="header-anchor" href="#실습-2-내-스킬-github에-올리기" aria-label="Permalink to &quot;실습 2: 내 스킬 GitHub에 올리기&quot;">​</a></h2><p>이제 아까 만든 이메일초안 스킬을 GitHub에 올려봅시다.</p><h3 id="step-1-저장소-만들기" tabindex="-1">Step 1: 저장소 만들기 <a class="header-anchor" href="#step-1-저장소-만들기" aria-label="Permalink to &quot;Step 1: 저장소 만들기&quot;">​</a></h3><p>Claude Code에게 이렇게 말하세요:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>내 스킬을 GitHub에 올리고 싶어.</span></span>
<span class="line"><span>my-claude-skills 라는 이름으로 GitHub 저장소를 만들고,</span></span>
<span class="line"><span>.claude/skills/ 폴더의 내용을 올려줘</span></span></code></pre></div><h3 id="step-2-확인하기" tabindex="-1">Step 2: 확인하기 <a class="header-anchor" href="#step-2-확인하기" aria-label="Permalink to &quot;Step 2: 확인하기&quot;">​</a></h3><p>Claude Code가 작업을 마치면 GitHub 저장소 URL을 알려줍니다.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://github.com/내사용자명/my-claude-skills</span></span></code></pre></div><p>브라우저에서 접속해보세요. 내 스킬 파일들이 올라가 있는 걸 확인할 수 있습니다!</p><div class="info custom-block"><p class="custom-block-title">이게 전부입니다</p><p>Git 명령어를 직접 칠 필요 없습니다. Claude Code에게 자연어로 말하면 <code>git init</code>, <code>git add</code>, <code>git commit</code>, <code>git push</code>를 전부 대신 해줍니다.</p></div><hr><h2 id="실습-3-친구-스킬-설치하기" tabindex="-1">실습 3: 친구 스킬 설치하기 <a class="header-anchor" href="#실습-3-친구-스킬-설치하기" aria-label="Permalink to &quot;실습 3: 친구 스킬 설치하기&quot;">​</a></h2><p>이번엔 반대로, <strong>다른 사람의 스킬을 내 컴퓨터에 설치</strong>해봅시다.</p><h3 id="step-1-상대방의-저장소-url-받기" tabindex="-1">Step 1: 상대방의 저장소 URL 받기 <a class="header-anchor" href="#step-1-상대방의-저장소-url-받기" aria-label="Permalink to &quot;Step 1: 상대방의 저장소 URL 받기&quot;">​</a></h3><p>옆 사람에게 GitHub 저장소 URL을 받으세요.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://github.com/친구사용자명/my-claude-skills</span></span></code></pre></div><h3 id="step-2-설치하기" tabindex="-1">Step 2: 설치하기 <a class="header-anchor" href="#step-2-설치하기" aria-label="Permalink to &quot;Step 2: 설치하기&quot;">​</a></h3><p>Claude Code에게:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>이 GitHub 저장소에서 스킬을 설치해줘:</span></span>
<span class="line"><span>https://github.com/친구사용자명/my-claude-skills</span></span></code></pre></div><h3 id="step-3-테스트" tabindex="-1">Step 3: 테스트 <a class="header-anchor" href="#step-3-테스트" aria-label="Permalink to &quot;Step 3: 테스트&quot;">​</a></h3><p>설치된 스킬을 실행해보세요. 다른 사람이 만든 스킬이 내 컴퓨터에서 동작합니다!</p><div class="tip custom-block"><p class="custom-block-title">스킬 공유의 힘</p><p>&quot;이메일초안&quot; 스킬 하나를 만들어서 공유하면:</p><ul><li>팀원 5명이 각자 쓸 수 있고</li><li>누가 개선하면 다 같이 업데이트할 수 있고</li><li>새로 입사한 사람도 바로 팀의 스킬을 쓸 수 있습니다</li></ul></div><hr><h2 id="스킬-공유의-의미-—-팀-활용-시나리오" tabindex="-1">스킬 공유의 의미 — 팀 활용 시나리오 <a class="header-anchor" href="#스킬-공유의-의미-—-팀-활용-시나리오" aria-label="Permalink to &quot;스킬 공유의 의미 — 팀 활용 시나리오&quot;">​</a></h2><p>혼자 쓰는 것도 좋지만, 팀에서 쓰면 효과가 배가 됩니다.</p><h3 id="시나리오-마케팅팀-5명이-같은-스킬을-쓴다면" tabindex="-1">시나리오: 마케팅팀 5명이 같은 스킬을 쓴다면? <a class="header-anchor" href="#시나리오-마케팅팀-5명이-같은-스킬을-쓴다면" aria-label="Permalink to &quot;시나리오: 마케팅팀 5명이 같은 스킬을 쓴다면?&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>팀장이 &quot;고객응대&quot; 스킬을 만듦</span></span>
<span class="line"><span>      ↓</span></span>
<span class="line"><span>GitHub에 올림</span></span>
<span class="line"><span>      ↓</span></span>
<span class="line"><span>팀원 4명이 각자 설치</span></span>
<span class="line"><span>      ↓</span></span>
<span class="line"><span>모든 팀원이 동일한 톤, 동일한 품질로 고객 응대</span></span>
<span class="line"><span>      ↓</span></span>
<span class="line"><span>한 명이 스킬을 개선하면 → 전체 업데이트</span></span></code></pre></div><table tabindex="0"><thead><tr><th>항목</th><th>스킬 공유 전</th><th>스킬 공유 후</th></tr></thead><tbody><tr><td>이메일 톤</td><td>사람마다 제각각</td><td>팀 전체 일관성</td></tr><tr><td>신입 온보딩</td><td>&quot;이렇게 써, 저렇게 써&quot; 교육</td><td>&quot;이 스킬 설치해&quot; 한마디</td></tr><tr><td>품질 관리</td><td>매번 검수 필요</td><td>스킬이 품질 보장</td></tr></tbody></table><hr><h2 id="cli-어려운-경우-대안" tabindex="-1">CLI 어려운 경우: 대안 <a class="header-anchor" href="#cli-어려운-경우-대안" aria-label="Permalink to &quot;CLI 어려운 경우: 대안&quot;">​</a></h2><p>터미널이 정 어렵다면 <strong>웹에서 직접 업로드</strong>하는 방법도 있습니다.</p><h3 id="github-웹으로-업로드하기" tabindex="-1">GitHub 웹으로 업로드하기 <a class="header-anchor" href="#github-웹으로-업로드하기" aria-label="Permalink to &quot;GitHub 웹으로 업로드하기&quot;">​</a></h3><ol><li><a href="https://github.com" target="_blank" rel="noreferrer">github.com</a> 로그인</li><li>오른쪽 상단 <strong>+</strong> → <strong>New repository</strong> 클릭</li><li>Repository name: <code>my-claude-skills</code> 입력</li><li><strong>Create repository</strong> 클릭</li><li><strong>uploading an existing file</strong> 링크 클릭</li><li>SKILL.md 파일을 드래그 앤 드롭</li><li><strong>Commit changes</strong> 클릭</li></ol><div class="info custom-block"><p class="custom-block-title">결과는 같습니다</p><p>CLI든 웹이든, GitHub 저장소에 SKILL.md 파일이 올라가는 것은 동일합니다. 편한 방법을 선택하세요!</p></div><hr><h2 id="완료-체크리스트" tabindex="-1">완료 체크리스트 <a class="header-anchor" href="#완료-체크리스트" aria-label="Permalink to &quot;완료 체크리스트&quot;">​</a></h2><ul><li>[ ] GitHub 계정이 있다</li><li>[ ] GitHub CLI로 로그인했다 (또는 웹으로 접속)</li><li>[ ] 내 스킬을 GitHub 저장소에 올렸다</li><li>[ ] 다른 사람의 스킬을 설치해봤다</li><li>[ ] &quot;팀에서 스킬을 공유하면 이런 효과가 있구나&quot; 이해했다</li></ul><hr><p><strong><a href="/학습자료/3-바이브코딩기초/3-1-바이브코딩">바이브코딩 기초 →</a></strong></p>`,60)])])}const b=a(l,[["render",n]]);export{u as __pageData,b as default};
